      tradeoffs: [["More threads", "Helps blocking workloads but increases switching."], ["Fewer threads", "Less overhead but may underuse resources."], ["Bounded pool", "Predictable default for a cache/server."]],
      failures: ["Using new Thread for every cache request.", "Confusing concurrency with parallelism.", "Ignoring blocked threads while sizing pools."],
      useWhen: ["Sizing executors.", "Explaining why thread pools exist."],
      avoidWhen: ["Do not micro-optimize switching before fixing blocking and lock contention."],
      code: "ExecutorService pool = Executors.newFixedThreadPool(Runtime.getRuntime().availableProcessors());\npool.submit(() -> cache.get(\"k1\"));",
      questions: [["EASY", "What is context switching?", "The CPU switches execution from one thread/process to another by saving and restoring state."], ["MEDIUM", "Why can it hurt cache performance?", "The resumed thread may need different memory, causing cache misses."], ["HARD", "How reduce context switch pressure?", "Use bounded executors, avoid blocking inside locks, and separate CPU-bound from IO-bound work."]],
      revision: "Context switching = scheduling overhead plus cache locality loss."
